function solve(nums, k) {
    nums.sort((a, b) => a - b);
    let max_size = 1;
    for (let i = 0; i < nums.length; i++) {
        let target = nums[i] * k;
        let low = i;
        let high = nums.length - 1;
        let res = i - 1;
        while (low <= high) {
            let mid = Math.floor((low + high) / 2);
            if (nums[mid] <= target) {
                res = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        let current_size = res - i + 1;
        if (current_size > max_size) {
            max_size = current_size;
        }
    }
    return nums.length - max_size;
}

